on conflict (source,external_order_id) do update set
  external_uuid=excluded.external_uuid,order_token=excluded.order_token,
  voucher_code=excluded.voucher_code,employee_id=excluded.employee_id,
  company_id=excluded.company_id,vendor_id=excluded.vendor_id,
  agreement_id=excluded.agreement_id,office_id=excluded.office_id,
  subtotal=excluded.subtotal,benefit_applied=excluded.benefit_applied,
  topup_amount=excluded.topup_amount,total=excluded.total,
  delivery_date=excluded.delivery_date,time_from=excluded.time_from,
  time_to=excluded.time_to,status=excluded.status,placed_at=excluded.placed_at,
  updated_at=now();